head.script:
// 전역 변수
scwin.memJson = $c.data.getMemInfo();
scwin.wrkNo = "";
scwin.fromDate = "";
scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd;
scwin.vLoginCoClsCd = $c.gus.cfIsNull(scwin.memJson.coClsCd) ? '' : scwin.memJson.coClsCd;
scwin.vUserHomeClsCd = scwin.memJson.userHomeClsCd;
scwin.vCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd;
scwin.isSubCompany = false;
scwin.privAdmin = scwin.memJson.privAdmin;
scwin.txtCoClsCd = "";
scwin.isStart = false; 

scwin.onpageload = function() {
    grd_section1.setStyle("display", "none");
    const codeOptions = [
        { grpCd : "CO012", compID : "acb_unit" }
    ];
    $c.data.setCommonCode(codeOptions);

    $c.gus.cfDisableKey();
};

scwin.ondataload = function() { 
    acb_unit.setSelectedIndex(1);
}

/**
 * UDC값
 */
scwin.onUdcCompleted = function() {
    ica_FromDate.setValue($c.date.getServerDateTime("yyyy"));
	scwin.f_LoadVer();
    scwin.f_setCompanyInfo();
    gr_btn.hide();

    if (ed_coCd.getValue() == "023") {
        scwin.f_retrieveCodeList("FI010", "003");
    } else {
        scwin.f_retrieveCodeList("FI010", "001");
    }
};

//-------------------------------------------------------------------------
// 각 Argument에 따른 PopUp을 호출 한다.
// 1:조회->부서
// code변수는 각 항목별 검색요청 값이다.
//-------------------------------------------------------------------------
scwin.f_openPopUp = async function(orgObjCd, orgObjNm, select_code, flag) {
    let cd, nm;

    if (flag == "ALL") {
        cd = "";
        nm = "";
    } else {
        cd = orgObjCd.getValue();
        nm = orgObjNm.getValue();
    }

    switch (select_code) {
        // 조회조건용 수금부서 PopUp 호출
        case '1':
            let param = ica_FromDate.getValue() + "0101" + ",,," + ed_coCd.getValue();
            await udc_acctDeptCdInfo8.cfCommonPopUp(scwin.udc_acctDeptCdInfo_callBackFunc,cd, nm,"T",null,null,null,null,param,",,,,,,1","450","500",null,null); // 귀속부서            
            break;
        default:
            await $c.win.alert("잘못된 Function호출 입니다. 관리자에게 문의하시기 바랍니다.");
            break;
    }
};

scwin.udc_acctDeptCdInfo_callBackFunc = function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_sacctDeptCd.setValue(rtnList[0]);
        ed_sacctDeptNm.setValue(rtnList[1]);
        if (!ed_sacctDeptCd.options) ed_sacctDeptCd.options = {};
        if (!ed_sacctDeptNm.options) ed_sacctDeptNm.options = {};
        ed_sacctDeptCd.options.hidVal = rtnList[0];
        ed_sacctDeptNm.options.hidVal = rtnList[1];
        dma_search.set("acctDeptLvl", rtnList[6]);
    } else {
        ed_sacctDeptCd.setValue("");
        ed_sacctDeptNm.setValue("");
        if (!ed_sacctDeptCd.options) ed_sacctDeptCd.options = {};
        if (!ed_sacctDeptNm.options) ed_sacctDeptNm.options = {};
        ed_sacctDeptCd.options.hidVal = "";
        ed_sacctDeptNm.options.hidVal = "";
        dma_search.set("acctDeptLvl", 0);
    }
};

//-------------------------------------------------------------------------
// PopUp창에서 사용되는 각 Cd,Nm에 대해서 POPUP표시 및 해당 값이 없을경우는 코드와 이름을 초기화 시킨다.
// flag값이 CD:코드변경이 없으면 POPUP안뛰움, NM:무조건 POPUP뛰움
//-------------------------------------------------------------------------
scwin.f_CheckPopUp = function(orgObjCd, orgObjNm, select_code, flag) {
    if (!orgObjCd.options) orgObjCd.options = {};
    if (!orgObjNm.options) orgObjNm.options = {};
    if (flag == "CD") {
        if (orgObjCd.getValue() == orgObjCd.options.hidVal) {
            return;
        } else {
            orgObjNm.setValue("");
        }
    } else {
        if (orgObjNm.getValue() == orgObjNm.options.hidVal) {
            return;
        } else {
            orgObjCd.setValue("");
        }
    }

    if (orgObjCd.getValue().trim() != "" || flag == "NM") {
        if (orgObjNm.getValue().trim() != "" || flag == "CD") {
            orgObjCd.setValue(orgObjCd.getValue().trim());
            orgObjNm.setValue(orgObjNm.getValue().trim());
            scwin.f_openPopUp(orgObjCd, orgObjNm, select_code, "NO");
        }
    } else {
        orgObjNm.setValue("");
        orgObjCd.setValue("");
        orgObjCd.options.hidVal = "";
    }
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function() {
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }

    scwin.isStart = true;
    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo('T');
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function(pWinCloseTF) {
    await udc_dongbuGroupCompanyInfo.cfCommonPopUp(scwin.udc_dongbuGroupCompanyInfo_callBackFunc
								,ed_coCd.getValue(), ed_coNm.getValue()
								,pWinCloseTF,null,null,null,null
								,null,null,null,null,null);  
};

scwin.udc_dongbuGroupCompanyInfo_callBackFunc = function(rtnList) {
    // SET
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_coCd.setValue(rtnList[0]);   // 코드
        ed_coNm.setValue(rtnList[5]);   // 회사명 
        scwin.txtCoClsCd = rtnList[1];
    } else {
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        scwin.txtCoClsCd = "";
    }

    if (ed_coCd.getValue() > ACConstants.CO_CD_DONGBU) {    // 자회사 회계 시스템 
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }

    if(scwin.isStart == true) {
        if ('T' == scwin.privAdmin || !scwin.isSubCompany) {    // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
            $c.gus.cfEnableObjects([ed_coCd, ed_coNm, btn_company]);
        } else {
            $c.gus.cfDisableObjects([ed_coCd, ed_coNm, btn_company]);
        }
    }
    scwin.isStart = false;
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    // 조회조건 필수사항 체크
    let ret = await $c.gus.cfValidate([ed_coCd,lc_bookClsCd,ica_FromDate, ed_sacctDeptCd, acb_version]);
    if (!ret) {
        return false;
    }

    dma_search.set("acctDeptCd", lc_acctDeptCd.getValue());
    dma_search.set("lowerDeptIncluYn","1");

	await scwin.f_JobCloseYN();
	$c.sbm.execute(sbm_search);
};

//-------------------------------------------------------------------------
// 마감체크
//-------------------------------------------------------------------------
scwin.f_JobCloseYN = async function() {
    let isClose = await udc_closeYn.cfJobCloseYN("CUR", scwin.fromDate, "00", ACConstants.CLOSE_DEPT_PROFIT_LOSS, "0", "", "", ed_coCd.getValue());
    dma_search.set("closeYn", isClose);
};

//-------------------------------------------------------------------------
// Ver정보를 가져온다.
//-------------------------------------------------------------------------
scwin.f_LoadVer = function() {
    // 작업구분코드 및 날짜 세팅함수 호출
    scwin.f_setWrkNoFromDate();

    const params = {
        sysCd:"CommonEBC", 
        queryId:"retrieveVersionInfo",
        param1:scwin.fromDate,
    };

    //데이터셋에 정보설정
    dma_version.setJSON(params);

    $c.sbm.execute(sbm_searchVer);
};

//-------------------------------------------------------------------------
// 최종 Ver을 설정
//-------------------------------------------------------------------------
scwin.f_SetFinalVer = function() {
    if (ds_version.getRowCount() < 1) return;
    let index = 0;
    for (let i = 0; i < ds_version.getRowCount(); i++) {
        if (ds_version.getCellData(i, "col3") == 1) {
            index = i;
            break;
        }
    }
    acb_version.setSelectedIndex(index);
};

//-------------------------------------------------------------------------
// 조회 및 마감확인시 작업코드 날짜 세팅하는 함수
//-------------------------------------------------------------------------
scwin.f_setWrkNoFromDate = function() {
    scwin.fromDate = ica_FromDate.getValue().trim() + "00";
};

//-------------------------------------------------------------------------
// 실적부서를 구한다.
//-------------------------------------------------------------------------
scwin.f_GetRsltsDept = async function() {
    if (! await $c.gus.cfValidate([ica_FromDate, ed_sacctDeptCd, acb_version])) {
        return;
    }
    dma_search.set("lowerDeptIncluYn", "1");

    const params = {
        sysCd:"ManagementProfitAndLossEBC", 
        queryId:"retrievePlanComparisonResultsAcctDept",
        param1:ed_sacctDeptCd.getValue().trim(),
        param2: dma_search.get("planYm"),
        param3: dma_search.get("lowerDeptIncluYn"),
        param4: dma_search.get("acctDeptLvl"),
        param5: dma_search.get("ver"),
        param7: dma_search.get("coCd")
    };

    //데이터셋에 정보설정
    dma_searchDept.setJSON(params);

    $c.sbm.execute(sbm_getDept);
};

//-------------------------------------------------------------------------
// 엑셀 파일 다운로드
//-------------------------------------------------------------------------
scwin.f_Export = async function(){
    let objGridName = gr_deptProfitLoss;
    if (await $c.win.confirm("Excel로 다운로드 하시겠습니까?")) {
        let exportFileName = "부서별손익계획조회_" + ed_sacctDeptNm.getValue().trim() + "_"+ica_FromDate.getValue().trim()+"_ver_"+acb_version.getValue()+".xlsx";
        $c.data.downloadGridViewExcel(objGridName,{ fileName: exportFileName, sheetName: "부서별손익계획조회" });
    }
}

//-------------------------------------------------------------------------
// 페이지정보를 초기화한다.
//-------------------------------------------------------------------------
scwin.f_ClearPaging = function() {
    pagingIndex.setValue("");
};


//-------------------------------------------------------------------------
// 페이지정보를 초기화한다.
//-------------------------------------------------------------------------
scwin.f_MoveToPage = function(pageNum) {
    let currentPage = 1;
    scwin.f_changeUnit();
    scwin.f_SetGridFormat(pageNum);
    //scwin.f_DisplayPaging(pageNum);
};


// //-------------------------------------------------------------------------
// // 페이지정보를 표시한다.
// //-------------------------------------------------------------------------
scwin.f_DisplayPaging = function(pageNum) {
    if ($c.gus.cfIsNull(pageNum)) pageNum = 1;

    let pagingStr = "<table width='100%' border='0' cellpadding='0' cellspacing='0'>" +
        "<tr>" +
        "  <td align='center' class='pagenumber_td'>";

    for (let i = 1; i <= 2; i++) {
        if (i != Number(pageNum)) {
            pagingStr += "<a href='#' onclick='scwin.f_MoveToPage(" + i + ")'>&nbsp;" + i + "&nbsp;</a>";
        } else {
            pagingStr += '&nbsp;[' + i + ']&nbsp;';
        }
    }
    pagingStr += "  </td>" +
        "</tr>" +
        "</table>";


    pagingIndex.setValue(pagingStr);
};

//-------------------------------------------------------------------------
// 그리드 지우기
//-------------------------------------------------------------------------
scwin.f_ClearGrid = function() {
    ds_deptProfitLoss.removeAll();
    scwin.f_ClearPaging();
};

//-------------------------------------------------------------------------
// 그리드 포맷설정
//-------------------------------------------------------------------------
scwin.f_SetGridFormat = function(pageNum) {
    if ($c.gus.cfIsNull(pageNum)) pageNum = 1;

    // 상반기/하반기 컬럼 ID 목록
    let halfYy1 = ["jan", "feb", "mar", "apr", "may", "jun", "halfYy"];
    let halfYy2 = ["jul", "aug", "sep", "oct", "nov", "dec", "halfYy2"];

    let showCols, hideCols;

    if (pageNum == 1) {
        showCols = halfYy1;
        hideCols = halfYy2;
    } else {
        hideCols = halfYy1;
        showCols = halfYy2;
    }

    // setColumnVisible API로 각 컬럼을 제어
        showCols.forEach(colId => {
            gr_deptProfitLoss.setColumnVisible(colId, true);
        });
        hideCols.forEach(colId => {
            gr_deptProfitLoss.setColumnVisible(colId, false);
        });
};

//-------------------------------------------------------------------------
// 그리드의 단위를 변경한다.
//-------------------------------------------------------------------------
scwin.f_changeUnit = function() {
    let unitValue = acb_unit.getValue();
    let unitAmt = 1;
    if (unitValue == "02") {
        unitAmt = 1000;
    } else if (unitValue == "03") {
        unitAmt = 1000000;
    } else if (unitValue == "04") {
        unitAmt = 100000000;
    }
    scwin.f_changeUnitAmt(unitAmt);
};

//-------------------------------------------------------------------------
// 그리드의 단위를 변경한다.
//-------------------------------------------------------------------------
scwin.f_changeUnitAmt = function(unitAmt) {
    if (!ds_deptProfitLossOriginal || ds_deptProfitLossOriginal.getRowCount() === 0) {
        return;
    }

    let calculatedData = ds_deptProfitLossOriginal.getAllJSON();
    const cols = ["amt", "jan", "feb", "mar", "apr", "may", "jun", "jul", "aug", "sep", "oct", "nov", "dec", "halfYy", "halfYy2"];


    for (let i = 0; i < calculatedData.length; i++) {
        let rowData = calculatedData[i];

        for (const colId of cols) {
            if (rowData.hasOwnProperty(colId)) {
                let originalValue = parseFloat(rowData[colId] || 0);
                rowData[colId] = Math.round(originalValue / unitAmt);
            }
        }
    }
    ds_deptProfitLoss.setJSON(calculatedData);
};



//-------------------------------------------                         
// 그리드 높이 늘리고 줄이기                         
//-------------------------------------------                         
function f_grdHeiht(gridNm, size) {                          

	var strHeight = gridNm.style.height ;                         
	var intHeight = parseInt(strHeight.replace("px",""));                         
	intHeight = intHeight + size;                         
	if (intHeight > 0 ) {                         
		gridNm.style.height = intHeight + "px";                           
	}                         
}

scwin.f_retrieveCodeList = function(grpCd, val) {
    const params = {
        sysCd:"CommonEBC", 
        queryId:"retrieveCommonFilterPopup",
        param1:grpCd,
        param2:val,
        param3:"",
    };

    //데이터셋에 정보설정
    dma_bookKndCd.setJSON(params);
    $c.sbm.execute(sbm_retrieveBookKnd);
};

scwin.DongbuGroupCompanyInfo_onclickEvent = async function (e) {
    scwin.f_PopUpCompanyInfo('F');
};

scwin.udc_acctDeptCdInfo8_onclickEvent = async function (e) {
    scwin.f_openPopUp(ed_sacctDeptCd,ed_sacctDeptNm,'1','ALL')
};

scwin.sbm_searchVer_submitdone = function (e) {
    scwin.f_SetFinalVer();
};

scwin.sbm_search_submitdone = async function (e) {
    //원본 데이터를 ds_deptProfitLossOriginal에 백업
    let originalData = ds_deptProfitLoss.getAllJSON();
    ds_deptProfitLossOriginal.setJSON(originalData);

    if (ds_deptProfitLoss.getRowCount() == 0) {
        await $c.win.alert(MSG_CM_ERR_003);
        scwin.f_ClearPaging();
    } else {
        scwin.f_MoveToPage(1);
        btn_pageNum1.addClass("on");
        btn_pageNum2.removeClass("on");
    }
    grd_section1.setStyle("display", "block");
    gr_btn.show();
    totalRows.setValue(ds_deptProfitLossOriginal.getRowCount());
};

scwin.btn_pageNum1_onclick = function (e) {
    scwin.f_SetGridFormat(1);
    btn_pageNum1.addClass("on");
    btn_pageNum2.removeClass("on");
};

scwin.btn_pageNum2_onclick = function (e) {
    scwin.f_SetGridFormat(2);
    btn_pageNum1.removeClass("on");
    btn_pageNum2.addClass("on");
};

scwin.ica_FromDate_onblur = function (e) {
    scwin.f_LoadVer();
};

scwin.udc_acctDeptCdInfo8_onblurCodeEvent = function (e) {
    scwin.f_CheckPopUp(ed_sacctDeptCd,ed_sacctDeptNm,'1','CD')
};

scwin.udc_acctDeptCdInfo8_onblurNameEvent = function (e) {
    scwin.f_CheckPopUp(ed_sacctDeptCd,ed_sacctDeptNm ,'1','NM')
};

scwin.acb_unit_onchange = function (info) {
    scwin.f_changeUnit();
};

scwin.lc_acctDeptCd_onchange = function (info) {
    if (ds_deptProfitLoss.getRowPosition() < 0) return;
	if ($c.gus.cfIsNull(lc_acctDeptCd.getValue())) return;
	scwin.f_Retrieve();
};

scwin.DongbuGroupCompanyInfo_onblurCodeEvent = function (e) {
    if (ed_coCd.getValue() != ""){
        scwin.f_PopUpCompanyInfo('T');
    }
    else{
        ed_coNm.setValue("");
    }

	 if (ed_coCd.getValue() == "023") {
    	scwin.f_retrieveCodeList("FI010", "003");
    } else {
    	scwin.f_retrieveCodeList("FI010", "001");
    }
};

scwin.sbm_getDept_submitdone = function (e) {
    scwin.f_Retrieve();
};

scwin.sbm_retrieveBookKnd_submitdone = function (e) {
    lc_bookClsCd.setSelectedIndex(0);
};

scwin.btn_clear_onclick = function (e) {
    $c.gus.cfInitObjects(table1,[ica_FromDate,ed_sacctDeptCd,ed_sacctDeptNm]);
};
